#include<bits/stdc++.h>
using namespace std;
class Tire_Tree_node {
		char data;
		bool ma;
		int cnt;
		Tire_Tree_node *it[128];
		Tire_Tree_node() {
			data = 0;
			ma = 0;
			cnt=0;
			memset(it, 0, sizeof(it));
		}
		~Tire_Tree_node() {
			data = 0;
			ma = 0;
			for (int i = 0; i < 128; ++i) {
				if (it[i] != nullptr) {
					delete it[i];
					it[i] = nullptr;
				}
			}

		}
		friend class Tire_Tree;

};
class Tire_Tree {
	public:
		Tire_Tree_node *root;
		Tire_Tree() {
			root = new Tire_Tree_node();
		}
		~Tire_Tree() {
			delete root;
		}
		void con(string& s, int x, Tire_Tree_node *root) {
			root->cnt++;
			if (x == s.size()) {

				root->ma = true;
				return;
			} else {
				if (root->it[s[x]] == nullptr) {

					root->it[s[x]] = new Tire_Tree_node();
					con(s, x + 1, root->it[s[x]]);
				} else {
					con(s, x + 1, root->it[s[x]]);
				}
			}
		}
		int qu1(string& s, int x, Tire_Tree_node *root) {
			if (x == s.size()) {

				return root->cnt;
			} else {
				if (root->it[s[x]] == nullptr) {
					return 0;
				} else {
					return qu1(s, x + 1, root->it[s[x]]);
				}
			}
		}
};

void solve() {
	Tire_Tree tree;
	int n, q;
	cin >> n >> q;
	for (int i = 1; i <= n; i++) {
		string a;
		cin >> a;
		tree.con(a, 0, tree.root);
	}
	for (int i = 1; i <= q; i++) {
		string a;
		cin >> a;
		cout << tree.qu1(a, 0, tree.root) << "\n";
	}
}
int main() {
	int t;
	cin >> t;
	while (t--) solve();
	return 0;
}
